import React, { useState } from 'react';

const App = () => {
  const [priceFormat, setPriceFormat] = useState('dollar');
  const formattedPrice = priceFormat === 'dollar' ? '$9.99' : '9.99 USD';

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 w-96">
        <h2 className="text-center">Simple Price Toggle Card</h2>
        <div className="flex justify-center items-center h-10 mt-4">
          <button className="bg-[#411C56] text-white p-2 rounded-md mr-2" onClick={() => setPriceFormat('dollar')}>Dollar</button>
          <button className="bg-[#411C56] text-white p-2 rounded-md" onClick={() => setPriceFormat('usd')}>USD</button>
        </div>
        <p className="text-center text-lg mt-4}>{formattedPrice}</p>
      </div>
    </div>
  );
};

export default App;
